  FROM ( 

SELECT
    *

  , 
    safe_cast(CONCAT(IFNULL(ad_words__device,''),IFNULL(criteo__device,''),IFNULL(google_analytics__device_category,''),IFNULL(bing__device_type,''),IFNULL(bing__device_os,''),IFNULL(facebook_ads__impression_device, ''),IFNULL(facebook_ads__conversion_device, '')) as string)
 AS `device` 
FROM ( 

SELECT
    
    safe_cast(
    safe_cast(CASE WHEN cast(nullif(trim(cast(`Date` AS string)), '') AS string) IN ('nan','None','','NaT') THEN NULL ELSE cast(nullif(trim(cast(`Date` AS string)), '') AS string) END as timestamp)
 as date)
 AS `date_id`

  , 
    safe_cast(CASE WHEN cast(nullif(trim(cast(`Connection_type_code` AS string)), '') AS string) IN ('nan','None','','NaT') THEN NULL ELSE cast(nullif(trim(cast(`Connection_type_code` AS string)), '') AS string) END as string)
 AS `connection_type_code`

