    safe_cast(CASE WHEN cast(nullif(trim(cast(`Connection_Id` AS string)), '') AS string) IN ('nan','None','','NaT') THEN NULL ELSE cast(nullif(trim(cast(`Connection_Id` AS string)), '') AS string) END as string)
 AS `connection_id`

  , 
