  , 
    safe_cast(CASE WHEN cast(nullif(trim(cast(`Cost` AS string)), '') AS string) IN ('nan','None','','NaT') THEN NULL ELSE cast(nullif(trim(cast(`Cost` AS string)), '') AS string) END as numeric)
